const tagsRaw = $('Ler Tags Banco').all().map(i => i.json);
const tagsList = Array.isArray(tagsRaw[0]) ? tagsRaw[0] : tagsRaw;
const tagsDisponiveis = [...new Set(tagsList.map(t => t.tag))].sort().join(', ');

const cenasComNota = cenas.filter(c => c.nota_correcao && c.nota_correcao.trim().length > 0);
const cenasSemNota = cenas.filter(c => !c.nota_correcao || c.nota_correcao.trim().length === 0);

if (cenas.length === 0) {
  return [{ json: { _semNotas: true, _cenasPendentes: [] } }];
}

// Sem cenas com nota → pula Claude, passa pendentes adiante
if (cenasComNota.length === 0) {
