  } }];
}

let efxParse = (efx) => {
  if (!efx) return [];
  if (typeof efx === 'string') { try { return JSON.parse(efx); } catch(e) { return []; } }
  return efx;
};

const cenasTexto = cenasComNota.map(c => {
  const efx = efxParse(c.efeitos_sonoros);
  return [
    `CENA ${c.numero} (id: ${c.id}):`,
    `Narração atual: "${c.narracao}"`,
    `Emoção atual: ${c.emocao}`,
    `Prompt movimento WAN atual: ${c.prompt_movimento_wan || '—'}`,
    `Prompt FLUX atual: ${c.prompt_flux || '—'}`,
    `Efeitos sonoros atuais: ${efx.map(e => (e.tipo === 'banco' ? 'banco:' + e.tag : 'stable_audio:' + e.prompt) + ' (w:' + e.weight + ')').join(', ') || 'nenhum'}`,
    `Personagem presente: ${c.personagem_presente}`,
    `Redux strength: ${c.redux_strength || 'null'}`,
    `NOTA DE CORREÇÃO: ${c.nota_correcao}`
  ].join('\n');
}).join('\n\n---\n\n');

const systemPrompt = `Você é o diretor técnico do canal O Mundo de Clay, um canal de horror claymation. Você recebe cenas com notas de correção em linguagem natural e determina EXATAMENTE o que precisa mudar em cada módulo.

MÓDULOS DISPONÍVEIS:
- IMAGEM: prompt_flux (gera nova imagem FLUX). Só mudar se a nota menciona problema visual na imagem (composição, enquadramento, cenário, personagem).
- ANIMAÇÃO: prompt_movimento_wan (gera novo vídeo WAN). Só mudar se a nota menciona movimento (muito sutil, muito rápido, direção errada).
- EFEITO: efeitos_sonoros (busca novos efeitos no banco). Só mudar se a nota menciona efeito sonoro (volume, tag errada, trocar efeito). Tags disponíveis no banco: ${tagsDisponiveis}.
- NARRAÇÃO: narracao e/ou emocao (regera TTS). Só mudar se a nota menciona texto da narração ou tom/emoção da voz.

REGRAS:
1. Se a nota NÃO menciona um módulo, NÃO o inclua em modulos_afetados.
2. Para IMAGEM: manter estrutura claymation_stoners... ANGLE... SUBJECT... LIGHT... FOREGROUND... MIDGROUND... BACKGROUND... COLOR. NUNCA partes do corpo no FOREGROUND.
3. Para ANIMAÇÃO: descrever UM movimento principal em inglês. Incluir "continuous motion throughout" ou "slow movement throughout".
4. Para EFEITO: usar APENAS tags existentes no banco. Cada efeito: {tipo: "banco", tag: "...", weight: 0.0-1.0}.
5. Para NARRAÇÃO: manter narração curta (máximo ~15 palavras). Emoções: calma, neutra, tensa, suspense, panico.
6. Se a nota pede ajuste de volume/weight de efeito, incluir EFEITO nos módulos afetados e retornar o array completo de efeitos_sonoros com weights ajustados.

Responda APENAS com JSON válido, sem markdown:\n{"cenas": [{"id": "uuid", "modulos_afetados": ["imagem"|"animacao"|"efeito"|"narracao"], "prompt_flux": "...", "prompt_movimento_wan": "...", "efeitos_sonoros": [...], "narracao": "...", "emocao": "..."}]}`;

return [{ json: {
  _systemPrompt: systemPrompt,
  _userMessage: 'Interprete as notas de correção e retorne as modificações necessárias:\n\n' + cenasTexto,
  _semNotas: false,
  _cenasPendentes: cenasSemNota
} }];

// Parse resposta do Claude e aplicar correções no Supabase
const response = $input.first().json;
const config = $('Configuração').first().json;
const videoId = $('Normalizar Input').first().json.video_id;

let cenasCorrigidas = [];
try {
  const text = response.text || response.response || '';
  const clean = text.replace(/```json|```/g, '').trim();
  cenasCorrigidas = JSON.parse(clean).cenas || [];
} catch(e) {
  throw new Error('Parse da resposta do Claude falhou: ' + e.message + '\nResposta: ' + JSON.stringify(response).substring(0, 500));
}

const headers = {
  'apikey': config.SUPABASE_SERVICE_KEY,
  'Authorization': 'Bearer ' + config.SUPABASE_SERVICE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=minimal'
};

const modulosNecessarios = new Set();

for (const c of cenasCorrigidas) {
  if (!c.id || !c.modulos_afetados) continue;
  const modulos = c.modulos_afetados;
  const updateBody = {};

  // IMAGEM
  if (modulos.includes('imagem') && c.prompt_flux) {
    updateBody.prompt_flux = c.prompt_flux;
    updateBody.imagem_status = 'pendente';
    modulosNecessarios.add('imagem');
  }

  // ANIMAÇÃO
  if (modulos.includes('animacao')) {
    if (c.prompt_movimento_wan) updateBody.prompt_movimento_wan = c.prompt_movimento_wan;
    updateBody.video_status = 'pendente';
    modulosNecessarios.add('animacao');
  }

  // EFEITO
  if (modulos.includes('efeito')) {
    if (c.efeitos_sonoros) updateBody.efeitos_sonoros = c.efeitos_sonoros;
    updateBody.efeito_status = 'pendente';
    modulosNecessarios.add('efeito');
  }

  // NARRAÇÃO
  if (modulos.includes('narracao')) {
    if (c.narracao) updateBody.narracao = c.narracao;
    if (c.emocao) updateBody.emocao = c.emocao;
    updateBody.tts_status = 'pendente';
    updateBody.tts_url = null;
    updateBody.duracao_real = null;
    modulosNecessarios.add('narracao');
  }

  // Limpar nota após aplicar
  updateBody.nota_correcao = null;

  try {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: config.SUPABASE_URL + '/rest/v1/cenas?id=eq.' + c.id,
      headers,
      body: updateBody
    });
  } catch(e) {}
}

const modulosList = Array.from(modulosNecessarios);

return [{ json: {
  _modulosNecessarios: modulosList,
  _precisaImagem: modulosList.includes('imagem'),
  _precisaAnimacao: modulosList.includes('animacao'),
  _precisaEfeito: modulosList.includes('efeito'),
  _precisaNarracao: modulosList.includes('narracao'),
  _cenasCorrigidas: cenasCorrigidas.length,
  videoId: videoId
} }];

// Dois caminhos de entrada:
// - Via "Aplicar Correções" (tinha notas): já vem com flags calculadas
// - Via "IF Sem Notas" saída true (sem notas): vem do Preparar Prompt Claude, só com _cenasPendentes

const data = $input.first().json;
const videoId = $('Normalizar Input').first().json.video_id;

// Caso 1: já vem com _modulosNecessarios (caminho com notas)
if (data._modulosNecessarios) {
  const modulos = data._modulosNecessarios || [];
  if (modulos.length === 0) {
    return [{ json: { _mensagem: 'Nenhum módulo precisa ser redisparado.', videoId: videoId } }];
  }
  return [{ json: {
    videoId: videoId,
    _precisaImagem: data._precisaImagem,
    _precisaNarracao: data._precisaNarracao,
    _precisaEfeito: data._precisaEfeito,
    _precisaAnimacao: data._precisaAnimacao,
    _modulosNecessarios: modulos
  } }];
}

// Caso 2: veio do IF Sem Notas true — calcular módulos a partir de _cenasPendentes
const cenasPendentes = data._cenasPendentes || [];
const modulosNecessarios = new Set();

for (const c of cenasPendentes) {
  if (c.imagem_status === 'pendente') modulosNecessarios.add('imagem');
  if (c.video_status === 'pendente') modulosNecessarios.add('animacao');
  if (c.efeito_status === 'pendente') modulosNecessarios.add('efeito');
  if (c.tts_status === 'pendente') modulosNecessarios.add('narracao');
}

const modulosList = Array.from(modulosNecessarios);

if (modulosList.length === 0) {
  return [{ json: { _mensagem: 'Nenhum módulo precisa ser redisparado.', videoId: videoId } }];
}

return [{ json: {
  videoId: videoId,
  _precisaImagem: modulosList.includes('imagem'),
  _precisaNarracao: modulosList.includes('narracao'),
  _precisaEfeito: modulosList.includes('efeito'),
  _precisaAnimacao: modulosList.includes('animacao'),
  _modulosNecessarios: modulosList
} }];

